record.field:
{
  "type": "object",
  "properties": {
    "servicio_code": {
      "type": "string",
      "description": "Pasá el valor del campo `code` EXACTO devuelto por consultar_servicios. Ejemplo concreto: si consultar_servicios devolvió {name:'Odontología General', code:'1233'}, acá pasás '1233' literal, NO el name ni un slug del name. Opcional: si vacío, lista profesionales sin filtrar por servicio."
    }
  },
  "required": []
}

{
  "type": "object",
  "properties": {
    "servicio_code": {
      "type": "string",
      "description": "OBLIGATORIO. Pasá el valor del campo `code` EXACTO devuelto por consultar_servicios. Ejemplo concreto: si consultar_servicios devolvió {name:'Odontología General', code:'1233'}, acá pasás '1233' literal. NO pasés el name ('Odontología General') ni un slug ('odontologia_general')."
    },
    "profesional_nombre": {
      "type": "string",
      "description": "Nombre parcial del profesional para filtrar (opcional)."
    },
    "fecha": {
      "type": "string",
      "description": "Fecha específica YYYY-MM-DD (opcional). Si no se indica, busca los próximos 14 días."
    }
  },
  "required": ["servicio_code"]
}

{
  "type": "object",
  "properties": {
    "servicio_code": {
      "type": "string",
      "description": "OBLIGATORIO. El valor del campo `code` EXACTO devuelto por consultar_servicios (ej. '1233'). NO el name ni un slug."
    }
  },
  "required": ["servicio_code"]
}

{
  "type": "object",
  "properties": {
    "vat": {"type": "string", "description": "Cédula o RUC."},
    "email": {"type": "string", "description": "Email del cliente."},
    "phone": {"type": "string", "description": "Teléfono. Si no se pasa, usa el wa_from de la sesión."},
    "name": {"type": "string", "description": "Nombre completo. Recomendado al crear."}
  },
  "required": []
}

{
  "type": "object",
  "properties": {
    "turno_id": {"type": "integer", "description": "ID del turno a reservar (obtenido de buscar_horarios_disponibles)."},
    "servicio_code": {"type": "string", "description": "Código del servicio elegido. Solo necesario cuando el turno ofrece varios."},
    "motivo": {"type": "string", "description": "Motivo o nota del cliente (opcional)."}
  },
  "required": ["turno_id"]
}

{
  "type": "object",
  "properties": {
    "motivo": {
      "type": "string",
      "description": "Razón breve del handoff (ej: 'cliente pidió hablar con persona', 'queja sobre cobro', 'consulta médica específica')."
    },
    "urgencia": {
      "type": "string",
      "enum": ["baja", "normal", "alta"],
      "description": "Default: normal."
    }
  },
  "required": ["motivo"]
}
